f=extractjsonfield(input:$str;field:$str):$str{
  let start=s.indexof(input;s.concat("\"";s.concat(field;"\":"))));
  if(start<0){<""};

  let valuestart=start+s.len(field)+3;
  let c=s.slice(input;valuestart;valuestart+1);

